  ('kyoto-sakura', 'kyoto', '08A', '{"culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Cherry blossom season', 'Sakura in Kyoto peaks late March into early April — brief, crowded, and unforgettable. Plan early if you''re chasing it.', '/guide/japan-cherry', null, null, '{"months":[3,4]}'::jsonb, 'late Mar–early Apr', 'curated', 80, null, null, null),
  ('patagonia-trekking', 'patagonia', '10S', '{"hiking"}', '{"activities","gear"}', 'schedule', 'lookahead', 'Patagonia trekking season', 'The W and the O trek best in the austral summer — roughly November to March, when the passes are open and the days are long.', '/guide/patagonia-trek', null, null, '{"months":[11,12,1,2,3]}'::jsonb, 'Nov–Mar', 'curated', 70, null, null, null),
  ('iceland-aurora', 'reykjavik', '03F', '{"adventure"}', '{"activities","move"}', 'schedule', 'lookahead', 'Northern Lights season', 'Iceland''s aurora window runs roughly September to March, on clear dark nights away from town lights.', '/region/03F', null, null, '{"months":[9,10,11,12,1,2,3]}'::jsonb, 'Sep–Mar', 'curated', 65, null, null, null),
  ('med-sailing-season', null, '02F', '{"sailing","yacht"}', '{"activities","move"}', 'schedule', 'soon', 'Mediterranean sailing season', 'The Med sails best May through October — settled weather, warm water, and the islands at their easiest to hop.', '/guide/med-sailing', null, null, '{"months":[5,6,7,8,9,10]}'::jsonb, 'May–Oct', 'curated', 60, null, null, null),
  ('galapagos-hammerhead-season', 'galapagos', '10S', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Galápagos — schooling hammerheads at their peak', 'The cooler, plankton-rich months bring the big schools of hammerheads to Wolf and Darwin. Seas can be livelier then and the water cooler — a wetsuit and some dive experience help; liveaboards plan around the conditions.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun–Nov (cooler, plankton-rich, big schools)', 'curated', 90, null, null, null),
  ('raja-ampat-best-season', 'raja-ampat', '07A', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Raja Ampat — calmest seas, richest reefs', 'In the dry months the seas settle and the water turns clear and calm — easy, comfortable diving over the richest reefs on earth. Gentle enough that newer divers do well here.', null, null, null, '{"months":[10,11,12,1,2,3,4]}'::jsonb, 'Oct–Apr (dry season, best conditions)', 'curated', 90, null, null, null),
  ('maldives-manta-whaleshark', 'maldives', '07A', '{"liveaboard","ocean"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Maldives — mantas & whale sharks gather', 'As the seasonal currents shift, mantas and whale sharks gather to feed. The water is warm and generally easy year-round; a liveaboard follows the calm, clear conditions to where the giants are.', null, null, null, null, 'year-round; peak aggregations vary by atoll/monsoon', 'curated', 70, null, null, null),
  ('cocos-island-season', 'cocos-island', '10S', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Cocos Island (Costa Rica) — pelagic season', 'A legendary big-animal site reached by an open-ocean crossing (~30+ hours) — the passage can be rough and the dives have current, so it suits experienced divers. The reward: schooling hammerheads and big pelagics.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun–Nov (rainier topside, best big-animal action)', 'curated', 70, null, null, null),
  ('maldives-honeymoon-dry', 'maldives', '07A', '{"romance"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Maldives — the calm, clear honeymoon season', 'Dry skies and glassy, warm lagoon water — calm and clear for swimming straight off your overwater villa. The classic honeymoon for a reason.', null, null, null, '{"months":[11,12,1,2,3,4]}'::jsonb, 'Nov–Apr (dry season)', 'curated', 90, null, null, null),
  ('bora-bora-honeymoon-dry', 'bora-bora', '09P', '{"romance"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Bora Bora & French Polynesia — dry-season honeymoon', 'The lagoon everyone pictures — calm, warm, impossibly clear in the dry months. Gentle water you can wade and snorkel right from the shore.', null, null, null, '{"months":[5,6,7,8,9,10]}'::jsonb, 'May–Oct (dry season)', 'curated', 90, null, null, null),
  ('santorini-shoulder-romance', 'santorini', '02F', '{"romance"}', '{"stay"}', 'lookahead', 'lookahead', 'Santorini — golden shoulder-season romance', 'Late spring and early fall: warm light, fewer crowds, the caldera all to yourselves at sunset.', null, null, null, '{"months":[4,5,6,9,10]}'::jsonb, 'late Apr–Jun & Sep–Oct (shoulder)', 'curated', 80, null, null, null),
  ('caribbean-dry-season', 'caribbean', '11C', '{"tropical"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Caribbean — peak dry-season sunshine', 'The reliable warm-and-clear stretch — gentle trade winds, calm bays, easy swimming and snorkeling. When home is grey and cold, this is the dependable escape.', null, null, null, '{"months":[12,1,2,3,4]}'::jsonb, 'Dec–Apr (dry season; the escape-the-cold window)', 'curated', 90, null, null, null),
  ('turks-caicos-best', 'turks-caicos', '11C', '{"tropical","liveaboard"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Turks & Caicos — Grace Bay at its finest', 'Grace Bay at its finest — calm, clear, gentle water over white sand, easy for everyone from toddlers to snorkelers. Best in the dry months; see the straight note on hurricane season for timing. (Our backyard.)', null, null, null, '{"months":[12,1,2,3,4]}'::jsonb, 'Dec–Apr (dry, calm); Atlantic hurricane window Jun–Nov noted', 'curated', 90, null, null, null),
  ('bali-dry-season', 'bali', '07A', '{"tropical","culture"}', '{"stay","activities"}', 'lookahead', 'soon', 'Bali — the dry, golden season', 'The dry season brings clear days, calm coastal water, and soft evenings — the island at its most welcoming and easy.', '/destination/bali', null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct (dry season)', 'curated', 80, null, null, null),
  ('danube-classic-season', 'danube', '01F', '{"river","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Danube — the classic cruising season', 'Vienna, Budapest, the Wachau in soft light — the heart of European river cruising.', null, null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct (cruising season)', 'curated', 80, null, null, null),
  ('danube-christmas-markets', 'danube', '01F', '{"river","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Danube & Rhine — Christmas Markets cruises', 'Late November into December: the rivers glow with market lights. A magical, bookable window.', null, null, null, '{"months":[11,12]}'::jsonb, 'late Nov–Dec (Christmas markets)', 'curated', 80, null, null, null),
  ('rhine-classic-season', 'rhine', '01F', '{"river","culture","wine"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Rhine — castles, vineyards, the gorge', 'The storybook stretch — terraced vines and hilltop castles, best in the warm season.', null, null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct', 'curated', 70, null, null, null),
  ('douro-season', 'douro', '01F', '{"river","wine","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Douro (Portugal) — wine country by water', 'Terraced port-wine valleys; the harvest months add a special glow.', null, null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct; harvest Sep–Oct', 'curated', 70, null, null, null),
  ('nile-best-season', 'nile', null, '{"river","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Nile — the cooler cruising months', 'Temples and timeless river light, when the heat eases to comfortable.', null, null, null, '{"months":[10,11,12,1,2,3,4]}'::jsonb, 'Oct–Apr (cooler)', 'curated', 70, null, null, null),
  ('atlantic-hurricane-season-frame', 'caribbean', '11C', '{"tropical","liveaboard","romance"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Atlantic hurricane season — the plain, reassuring frame', 'Season runs Jun 1–Nov 30, but most major-hurricane activity is Aug–Oct (peak around mid-September). Most of the season, most places are doing exactly what you came for. And it''s never an ambush — systems are tracked days out, with warnings well ahead. Read the season, travel it wisely.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun 1–Nov 30; peak mid-Aug–mid-Oct', 'curated', 80, null, null, null),
  ('tci-hurricane-aware', 'turks-caicos', '11C', '{"tropical","liveaboard"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Turks & Caicos — hurricane-season straight talk', 'Our home waters, straight: T&C sits in the Atlantic corridor, so respect the Aug–Oct peak and plan a little. The flip side — the rest of the year is glorious, Grace Bay calm is the norm, and you''ll have days of warning if anything brews. Travel the shoulder months, protect your trip when you book, and you travel it like the locals: relaxed and ready.', null, null, null, '{"months":[8,9,10]}'::jsonb, 'respect Aug–Oct; relish the rest', 'curated', 80, null, null, null),
  ('southern-caribbean-below-belt', 'southern-caribbean', '11C', '{"tropical","liveaboard"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Southern Caribbean (Aruba/Bonaire/Curaçao) — below the hurricane belt', 'Happy geography: the ABC islands plus Trinidad & Tobago sit far enough south that most Atlantic storms pass to the north — widely known as below the hurricane belt, the lowest-risk corner of the Caribbean. Lower-risk isn''t no-risk, but for warm water with the calmest odds, the southern islands are a smart, sunny choice nearly year-round.', null, null, null, null, 'lowest-risk Caribbean zone, near year-round', 'curated', 70, null, null, null),
  ('honeymoon-hurricane-protect', 'caribbean', '11C', '{"romance","tropical"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Honeymoons — protect the once-in-a-lifetime trip', 'A honeymoon is worth protecting properly. The romance sweet spots (late fall through spring) sit largely outside the hurricane peak — calmest beaches, calmest skies. Book early, and add trip protection at the time you book (the detail couples most often miss): insurance covers storm disruption only if bought before a storm is named.', null, null, null, null, 'late fall–spring (outside peak)', 'curated', 80, null, null, null),
  ('dive-liveaboard-hurricane', 'caribbean', '11C', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Dive liveaboards — the pros watch the weather for you', 'Liveaboard trips are planned far ahead on tight weather windows — which works in your favor: operators watch the tropics professionally and reroute or reschedule around weather as routine. Book outside the Aug–Oct peak where you can, protect the trip when you reserve, and let the captain and the forecast do the worrying.', null, null, null, null, 'favor outside Aug–Oct peak', 'curated', 70, null, null, null),
  ('serengeti-calving', 'serengeti', '05A', '{"safari"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Serengeti calving — the great birth on the southern plains', 'Late January into March, the southern Serengeti and Ndutu fill with newborn wildebeest — thousands a day — and the predators that follow. It''s the most concentrated, most predictable stretch of the migration year; the exact start shifts a week or two with the short rains.', null, null, null, '{"months":[1,2,3]}'::jsonb, 'late Jan–mid Mar (calving)', 'curated', 85, null, null, null),
  ('okavango-flood-paradox', 'okavango', '06A', '{"safari"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Okavango Delta — peak flood in the dry months', 'The Delta''s paradox: floodwaters from the Angolan highlands arrive in the dry season, peaking roughly June through August when local rain has stopped. That''s mokoro and water-channel season — the iconic Okavango. Exact flood timing and reach vary year to year, so flexible dates and an operator''s current read help.', null, null, null, '{"months":[6,7,8,9]}'::jsonb, 'peak flood ~Jun–Aug (varies yearly)', 'curated', 80, null, null, null),
  ('ngorongoro-crater-season', 'ngorongoro', '05A', '{"safari"}', '{"activities","stay"}', 'schedule', 'lookahead', 'Ngorongoro Crater — Big Five, any month', 'The crater holds resident game year-round, so there''s no bad month. June through October is driest, with the clearest views and the most predator action; the green months (Nov–May) bring lush scenery, fewer vehicles, and lower rates.', null, null, null, null, 'year-round; Jun–Oct driest', 'curated', 70, null, null, null),
  ('galapagos-whale-sharks', 'galapagos', '10S', '{"expedition","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Galápagos — whale sharks at Darwin & Wolf', 'From July into November the cool, plankton-rich upwelling draws giant — often pregnant — whale sharks to the far-northern islands of Darwin and Wolf. It''s a liveaboard-dive window; the day boats don''t reach that far.', null, null, null, '{"months":[7,8,9,10,11]}'::jsonb, 'Jul–Nov (peak Jul–Oct)', 'curated', 80, null, null, null),
  ('amazon-water-levels', 'amazon', '10S', '{"expedition","river"}', '{"activities","stay"}', 'schedule', 'lookahead', 'Amazon — high water vs low water changes the trip', 'The Amazon has two faces. High water (roughly December–May) floods the forest, opening skiff routes into hidden creeks and lakes. Low water (roughly June–November) exposes riverbanks and sandbars for jungle walks. Neither is off-season — the water level just shifts what you do; the transition timing varies year to year.', null, null, null, null, 'high water ~Dec–May / low water ~Jun–Nov (varies yearly)', 'curated', 70, null, null, null),
  ('raja-ampat-dry-season', 'raja-ampat', '07A', '{"liveaboard","ocean"}', '{"activities"}', 'schedule', 'lookahead', 'Raja Ampat — calm seas, peak visibility', 'The dry months bring calm seas and the clearest water over the richest reefs on earth — roughly October through April, with the glassiest conditions around January–February. Most liveaboards pause July–August in the windy season.', null, null, null, '{"months":[10,11,12,1,2,3,4]}'::jsonb, 'Oct–Apr (calmest Jan–Feb; liveaboards pause Jul–Aug)', 'curated', 88, null, null, null),
  ('galapagos-cool-pelagic', 'galapagos', '10S', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Galápagos — the cool-season big animals', 'The cool, plankton-rich Humboldt months — roughly June to November — bring the big pelagic action to Darwin and Wolf. Whale sharks are most reliable July through October; the seas run livelier and the water cooler, so it suits more experienced divers. Aggregations vary year to year.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun–Nov cool season; whale sharks peak Jul–Oct (varies yearly)', 'curated', 88, null, null, null),
  ('red-sea-best-season', 'red-sea', '04A', '{"liveaboard","ocean"}', '{"activities"}', 'schedule', 'lookahead', 'Red Sea — the calm shoulder-season window', 'Calm seas and warm water make spring and autumn — roughly March–May and September–November — the sweet spot for Egyptian liveaboards. For sharks: scalloped hammerhead schools peak around May–July, and oceanic whitetips around October–December (varies yearly). Winter is divable but cooler.', null, null, null, '{"months":[3,4,5,9,10,11]}'::jsonb, 'Mar–May & Sep–Nov (hammerheads ~May–Jul, oceanic whitetips ~Oct–Dec)', 'curated', 78, null, null, null),
  ('douro-harvest', 'douro', '01F', '{"river","wine","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Douro Valley — the grape harvest glow', 'The vindima — harvest in the terraced port-wine valleys — runs roughly mid-September into mid-October, the most atmospheric stretch of the Douro cruising season. Exact picking dates shift year to year with the weather and the grapes.', null, null, null, '{"months":[9,10]}'::jsonb, 'harvest ~mid-Sep–mid-Oct (varies yearly); cruise season Apr–Oct', 'curated', 76, null, null, null),
  ('mekong-high-water', 'mekong', '07A', '{"river","culture"}', '{"activities","stay"}', 'lookahead', 'lookahead', 'Mekong — high water opens the great lake', 'When the river runs high — roughly mid-August into November — ships can reach the Tonlé Sap and dock for the Siem Reap excursion. November is the rare sweet spot where high water and the cool, dry early-season weather overlap. Flood timing shifts year to year.', null, null, null, '{"months":[8,9,10,11]}'::jsonb, 'high water ~mid-Aug–Nov (varies yearly); Nov = best weather + access', 'curated', 76, null, null, null),
  ('rhine-cruise-season', 'rhine', '01F', '{"river","culture","wine"}', '{"activities","stay"}', 'schedule', 'lookahead', 'Rhine — castles, vineyards, the gorge', 'The Rhine cruises roughly April through October, with the warmest, busiest stretch June–August and the best-value light in the late-April–June and September shoulders. Late November into December brings the Christmas-market sailings.', null, null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct (peak Jun–Aug); Christmas markets late Nov–Dec', 'curated', 74, null, null, null),
  ('maldives-dry-season', 'maldives', '07A', '{"tropical"}', '{"stay","activities"}', 'schedule', 'lookahead', 'Maldives — the calm, clear dry season', 'From November to April the northeast monsoon brings clear skies, gentle winds and glassy lagoon water — calm and warm for swimming straight off your villa. Peak conditions are December–March.', null, null, null, '{"months":[11,12,1,2,3,4]}'::jsonb, 'Nov–Apr dry season (NE monsoon; peak Dec–Mar)', 'curated', 86, null, null, null),
  ('seychelles-calm-transitions', 'seychelles', '07A', '{"tropical"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Seychelles — the calm in between the trades', 'Twice a year the trade winds change over and the sea goes glassy — roughly April–May and October–November. These transition months bring the calmest water and the best underwater visibility of the year.', null, null, null, '{"months":[4,5,10,11]}'::jsonb, 'Apr–May & Oct–Nov (trade-wind transitions, calmest seas)', 'curated', 78, null, null, null),
  ('fiji-dry-season', 'fiji', '09P', '{"tropical"}', '{"stay","activities"}', 'schedule', 'lookahead', 'Fiji — the dry, golden season', 'May through October is Fiji''s dry season — cooler, less rain, steady trade winds and clear water for diving. The most settled months are June–August.', null, null, null, '{"months":[5,6,7,8,9,10]}'::jsonb, 'May–Oct dry season (driest Jun–Aug)', 'curated', 78, null, null, null),
  ('santorini-shoulder', 'santorini', '02F', '{"romance"}', '{"stay"}', 'lookahead', 'lookahead', 'Santorini — warm light, fewer crowds', 'Late spring and early autumn — roughly May–June and September into mid-October — bring warm seas, comfortable days and the caldera without the high-summer crush. Late September is many travelers'' favorite.', null, null, null, '{"months":[5,6,9,10]}'::jsonb, 'May–Jun & Sep–mid-Oct (shoulder)', 'curated', 80, null, null, null),
  ('bali-dry-season-romance', 'bali', '07A', '{"romance","tropical"}', '{"stay","activities"}', 'schedule', 'soon', 'Bali — the dry, golden season', 'Bali''s dry season runs April through October — clear days, calm coastal water, soft evenings. May, June and September are the sweet spot, idyllic and quieter than the July–August peak.', null, null, null, '{"months":[4,5,6,7,8,9,10]}'::jsonb, 'Apr–Oct dry season (sweet spot May/Jun/Sep)', 'curated', 80, null, null, null),
  ('amalfi-shoulder', 'amalfi-coast', '02F', '{"romance"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Amalfi Coast — the warm, uncrowded edges', 'May–June and September are the Amalfi sweet spot — warm, golden, and calmer than the August crush, with ferries and villages in full swing. The coast is open roughly April through October; in winter much of it closes down.', null, null, null, '{"months":[5,6,9]}'::jsonb, 'May–Jun & Sep shoulder (open ~Apr–Oct; winter largely closed)', 'curated', 78, null, null, null),
  ('south-luangwa-dry-walking', 'south-luangwa', '06A', '{"safari"}', '{"activities","stay"}', 'schedule', 'lookahead', 'South Luangwa — the walking-safari season', 'As the dry season deepens — roughly June to October — game gathers along the Luangwa River and the thinned bush makes this the home of the walking safari, strongest from July on. Many camps close in the green months (~Nov–Apr).', null, null, null, '{"months":[6,7,8,9,10]}'::jsonb, 'Jun–Oct dry (walking prime Jul–Oct; camps close ~Nov–Apr)', 'curated', 82, null, null, null),
  ('etosha-dry-waterholes', 'etosha', '06A', '{"safari"}', '{"activities","stay"}', 'schedule', 'lookahead', 'Etosha — the great waterhole gathering', 'As the bush dries out — roughly May to October — animals are drawn to Etosha''s waterholes, where you can watch many species drink in one spot. Concentrations build to a peak in September–October, just before the rains.', null, null, null, '{"months":[5,6,7,8,9,10]}'::jsonb, 'May–Oct dry (peak waterholes Sep–Oct)', 'curated', 80, null, null, null),
  ('svalbard-arctic-summer', 'svalbard', '03F', '{"expedition","ocean"}', '{"activities","move"}', 'schedule', 'lookahead', 'Svalbard — the Arctic summer window', 'The expedition-cruise season runs roughly late May through September, with the core June–August offering the warmest conditions and the best ice access to the remote north. Midnight sun lasts into late August; the season''s edges shift year to year with the ice.', null, null, null, '{"months":[5,6,7,8,9]}'::jsonb, 'late May–Sep, core Jun–Aug (ice-dependent edges; midnight sun ~Apr 20–Aug 22)', 'curated', 80, null, null, null),
  ('kimberley-dry-expedition', 'kimberley', '09P', '{"expedition","ocean"}', '{"activities","move"}', 'schedule', 'lookahead', 'Kimberley — the dry-season expedition window', 'The Kimberley coast cruises in the dry season — roughly April through September at the core, with March and October shoulders. Early in the window the waterfalls still run hard; by August–September humpbacks pass through.', null, null, null, '{"months":[3,4,5,6,7,8,9,10]}'::jsonb, 'Apr–Sep core (Mar/Oct shoulder); waterfalls early, whales Aug–Sep', 'curated', 78, null, null, null)
